butes())do O=true break end if O then if not F.Parent:FindFirstChild("BerryESP")then local U=Instance.new("BillboardGui",F.Parent)U.Name="BerryESP"U.ExtentsOffset=Vector3.new(0,2,0)U.Size=UDim2.new(1,200,1,30)U.AlwaysOnTop=true local O=Instance.new("TextLabel",U)O.Font=Enum.Font.GothamSemibold O.TextSize=14 O.TextWrapped=true O.Size=UDim2.new(1,0,1,0)O.BackgroundTransparency=1 O.TextStrokeTransparency=.5 O.TextColor3=Color3.fromRGB(255,255,0)end if U then local O=math.floor(((F.Parent:GetPivot()).Position-U.Position).Magnitude)for U,n in pairs(F:GetAttributes())do F.Parent.BerryESP.TextLabel.Text=tostring(n)..("\n"..(O.."m"))end end else local U=F.Parent:FindFirstChild("BerryESP")if U then U:Destroy()end end end)end end function U.UpdateDevilESP(U)for O,F in pairs(workspace:GetChildren())do pcall(function()local O="NameEsp"..U if(getgenv()).DevilFruitESP and string.find(F.Name,"Fruit")then local U=F:FindFirstChild("Handle")if not U then return end local n=W.Character and W.Character:FindFirstChild("Head")local p=n and math.floor((n.Position-U.Position).Magnitude/3)or 0 if not U:FindFirstChild(O)then local n=Instance.new("BillboardGui",U)n.Name=O n.ExtentsOffset=Vector3.new(0,1,0)n.Size=UDim2.new(1,200,1,30)n.AlwaysOnTop=true local W=Instance.new("TextLabel",n)W.Font=Enum.Font.GothamSemibold W.TextSize=14 W.TextWrapped=true W.Size=UDim2.new(1,0,1,0)W.BackgroundTransparency=1 W.TextStrokeTransparency=.5 W.TextColor3=Color3.fromRGB(255,255,255)W.Text=F.Name..("\n"..(p.." Distance"))else U[O].TextLabel.Text=F.Name..("\n"..(p.." Distance"))end else if F:FindFirstChild("Handle")then local U=F.Handle:FindFirstChild(O)if U then U:Destroy()end end end end)end end function U.UpdatePlayerESP(U)for O,F in pairs(O:GetChildren())do pcall(function()if not F.Character then return end local O=F.Character:FindFirstChild("Head")if not O then return end local n="NameEsp"..U if(getgenv()).ESPPlayer then if not O:FindFirstChild(n)then local U=Instance.new("BillboardGui",O)U.Name=n U.ExtentsOffset=Vector3.new(0,1,0)U.Size=UDim2.new(1,200,1,30)U.AlwaysOnTop=true local p=Instance.new("TextLabel",U)p.Font=Enum.Font.GothamSemibold p.TextSize=14 p.TextWrapped=true p.Size=UDim2.new(1,0,1,0)p.BackgroundTransparency=1 p.TextStrokeTransparency=.5 p.TextColor3=F.Team==W.Team and Color3.new(0,1,0)or Color3.new(1,0,0)else local U=W.Character and W.Character:FindFirstChild("Head")if U then local W=math.floor((U.Position-O.Position).Magnitude/3)local p=math.floor((F.Character.Humanoid.Health*100)/F.Character.Humanoid.MaxHealth)O[n].TextLabel.Text=F.Name..(" | "..(W..(" m\nHP: "..(p.."%"))))end end else local U=O:FindFirstChild(n)if U then U:Destroy()end end end)end end return U
